import java.util.*;class StockSpan{public static void main(String[]a){Scanner s=new Scanner(System.in);int n=s.nextInt();int[] p=new int[n];for(int i=0;i<n;i++)p[i]=s.nextInt();int[] span=new int[n];Stack<Integer> st=new Stack<>();for(int i=0;i<n;i++){while(!st.isEmpty()&&p[st.peek()]<=p[i])st.pop();span[i]=st.isEmpty()?i+1:i-st.peek();st.push(i);}for(int i=0;i<n;i++)System.out.print(span[i]+" ");}}